import{_ as t,o as a,c as n,a4 as o}from"./chunks/framework.Cqne-ChA.js";const l=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/zopen-promote.md","filePath":"reference/zopen-promote.md","lastUpdated":1776692264000}'),r={name:"reference/zopen-promote.md"};function d(p,e,i,f,m,s){return a(),n("div",null,[...e[0]||(e[0]=[o('<div class="man-page-content" data-v-c1d2836f><h1 align="center" data-v-c1d2836f>ZOPEN-VERSION</h1><h2 data-v-c1d2836f>NAME <a name="NAME" data-v-c1d2836f></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f>zopen-version ‚ąí manual page for zopen-version 0.8.4</p><h2 data-v-c1d2836f>SYNOPSIS <a name="SYNOPSIS" data-v-c1d2836f></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f><b data-v-c1d2836f>zopen</b><i data-v-c1d2836f>promote</i> [<i data-v-c1d2836f>OPTION</i>] [<i data-v-c1d2836f>DESTINATION</i>]...</p><h2 data-v-c1d2836f>DESCRIPTION <a name="DESCRIPTION" data-v-c1d2836f></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f>zopen‚ąípromote is a utility for zopen community to generate a clone of an existing zopen environment. For example, a user can install to a test area, validate the behavior, and promote to a production area.</p><h2 data-v-c1d2836f>OPTIONS <a name="OPTIONS" data-v-c1d2836f></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f><b data-v-c1d2836f>‚ąícp</b>, <b data-v-c1d2836f>‚ąí‚ąíconfigperms</b> [PERMISSIONS]</p><p style="margin-left:22%;" data-v-c1d2836f>Update the permissions for the configuration file &lt;promotedroot&gt;/etc/zopen‚ąíconfig with the given [PERMISSIONS] string, specified in symbolic mode.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąíf</b>, <b data-v-c1d2836f>‚ąí‚ąífrom</b></p><p style="margin-left:22%;" data-v-c1d2836f>[DIRECTORY] The zopen environment to copy from; if not present, the default is taken from ZOPEN_ROOTFS (the current zopen environment).</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąíg</b>, <b data-v-c1d2836f>‚ąí‚ąígroup</b> [GROUP]</p><p style="margin-left:22%;" data-v-c1d2836f>Change group of promoted environment files from default.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąíh</b>, ‚ąí?, <b data-v-c1d2836f>‚ąí‚ąíhelp</b></p><p style="margin-left:22%;" data-v-c1d2836f>Display this help and exit.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąí‚ąíkeepzopentooling</b></p><p style="margin-left:22%;" data-v-c1d2836f>Install the zopen admin tools into the promoted environment for zopen system administration.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąío</b>, <b data-v-c1d2836f>‚ąí‚ąíowner</b> [OWNER]</p><p style="margin-left:22%;" data-v-c1d2836f>Change owner of promoted environment files from current user.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąív</b>, <b data-v-c1d2836f>‚ąí‚ąíverbose</b></p><p style="margin-left:22%;" data-v-c1d2836f>Run in verbose mode.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąí‚ąíversion</b></p><p style="margin-left:22%;" data-v-c1d2836f>Display version information.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąíy</b>, <b data-v-c1d2836f>‚ąí‚ąíyes</b></p><p style="margin-left:22%;" data-v-c1d2836f>Automatically answer ‚Äôyes‚Äô to prompts; existing target filesystems will be purged before promote occurs.</p><p style="margin-left:11%;" data-v-c1d2836f><b data-v-c1d2836f>‚ąízp</b>, <b data-v-c1d2836f>‚ąí‚ąízopenperms</b> [PERMISSIONS]</p><p style="margin-left:22%;" data-v-c1d2836f>Update the permissions for all files within the promoted zopen environment with the given [PERMISSIONS] string, specified in symbolic mode.</p><h2 data-v-c1d2836f>EXAMPLES <a name="EXAMPLES" data-v-c1d2836f></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f>zopen promote</p><p style="margin-left:22%;" data-v-c1d2836f>Interactively promote current zopen environment.</p><p style="margin-left:11%;" data-v-c1d2836f>zopen promote /prod</p><p style="margin-left:22%;" data-v-c1d2836f>Promote current zopen environment to ‚Äô/prod‚Äô, setting file ownership to current user and group to default.</p><p style="margin-left:11%;" data-v-c1d2836f>zopen promote /prod ‚ąí‚ąíowner FOO</p><p style="margin-left:22%;" data-v-c1d2836f>Promote current zopen environment to ‚Äô/prod‚Äô, setting file ownership to ‚ÄôFOO‚Äô and group to default.</p><p style="margin-left:11%;" data-v-c1d2836f>zopen promote /prod ‚ąí‚ąígroup BAR</p><p style="margin-left:22%;" data-v-c1d2836f>Promote current zopen environment to ‚Äô/prod‚Äô, setting file ownership to current user and group to ‚ÄôBAR‚Äô.</p><p style="margin-left:11%;" data-v-c1d2836f>zopen promote /mytest ‚ąícp g‚ąíwx,o‚ąírwx ‚ąízp g‚ąírwx,o‚ąírwx ‚ąí‚ąíowner FOO</p><p style="margin-left:22%;" data-v-c1d2836f>Promote current zopen environment to ‚Äô/mytest‚Äô, allowing only the current user to source the zopen‚ąíconfig environment file and only permit access to zopen environment files to the user ‚ÄôFOO‚Äô.</p><h2 data-v-c1d2836f>AUTHOR <a name="AUTHOR" data-v-c1d2836f></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f>Written by contributors to the zopen community. &lt;https://github.com/zopencommunity/meta/graphs/contributors&gt;</p><h2 data-v-c1d2836f>REPORTING BUGS <a name="REPORTING BUGS" data-v-c1d2836f></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f>Report bugs at https://github.com/zopencommunity/meta/issues</p><p style="margin-left:11%;margin-top:1em;" data-v-c1d2836f>This is free software: you are free to change and redistribute it under the terms of the Apache License, Version 2.0. &lt;https://www.apache.org/licenses/LICENSE‚ąí2.0.html&gt; There is NO WARRANTY, to the extent permitted by law.</p></div>',1)])])}const v=t(r,[["render",d],["__scopeId","data-v-c1d2836f"]]);export{l as __pageData,v as default};
